import React, { useState } from 'react';
import { Menu, X } from 'lucide-react';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);

  const navLinks = [
    { name: 'Home', href: '#home' },
    { name: 'Features', href: '#features' },
    { name: 'Testimonials', href: '#testimonials' },
    { name: 'Pricing', href: '#pricing' },
    { name: 'Contact', href: '#contact' },
  ];

  return (
    <nav className="bg-white text-zinc-900 p-6 sm:p-8 sticky top-0 z-50">
      <div className="container mx-auto flex justify-between items-center">
        <a href="#home" className="text-2xl font-bold text-zinc-900">
          NexusCore
        </a>

        {/* Desktop Navigation */}
        <div className="hidden md:flex items-center space-x-8">
          {navLinks.map((link) => (
            <a
              key={link.name}
              href={link.href}
              className="text-zinc-700 hover:text-zinc-900 transition duration-300 ease-in-out font-medium"
            >
              {link.name}
            </a>
          ))}
          <button className="px-6 py-3 rounded-md bg-zinc-600 text-white font-medium hover:bg-zinc-700 transition duration-300 ease-in-out focus:outline-none focus:ring-2 focus:ring-zinc-500 focus:ring-offset-2">
            Login
          </button>
          <button className="px-6 py-3 rounded-md bg-zinc-800 text-white font-medium hover:bg-zinc-900 transition duration-300 ease-in-out focus:outline-none focus:ring-2 focus:ring-zinc-700 focus:ring-offset-2">
            Sign Up
          </button>
        </div>

        {/* Mobile Menu Button */}
        <div className="md:hidden">
          <button onClick={() => setIsOpen(!isOpen)} className="text-zinc-900 focus:outline-none">
            {isOpen ? <X size={28} /> : <Menu size={28} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-white mt-4 pb-4 border-t border-zinc-200">
          <div className="flex flex-col space-y-4 px-6 pt-4">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.href}
                onClick={() => setIsOpen(false)}
                className="block text-zinc-700 hover:text-zinc-900 transition duration-300 ease-in-out font-medium py-2"
              >
                {link.name}
              </a>
            ))}
            <button className="w-full px-6 py-3 rounded-md bg-zinc-600 text-white font-medium hover:bg-zinc-700 transition duration-300 ease-in-out focus:outline-none focus:ring-2 focus:ring-zinc-500 focus:ring-offset-2">
              Login
            </button>
            <button className="w-full px-6 py-3 rounded-md bg-zinc-800 text-white font-medium hover:bg-zinc-900 transition duration-300 ease-in-out focus:outline-none focus:ring-2 focus:ring-zinc-700 focus:ring-offset-2">
              Sign Up
            </button>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

