import React, { useState } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';

const TestimonialCarousel = () => {
  const testimonials = [
    {
      quote: "NexusCore has revolutionized our operations. The automation features are incredibly powerful and easy to use. Our team's productivity has soared!",
      author: 'Jane Doe',
      title: 'CEO, TechSolutions Inc.',
    },
    {
      quote: "The seamless integration with our existing systems made adoption a breeze. NexusCore is an essential tool for any modern business looking to scale.",
      author: 'John Smith',
      title: 'CTO, Global Innovations',
    },
    {
      quote: "We've seen a significant reduction in manual errors and a dramatic increase in efficiency since implementing NexusCore. Highly recommend!",
      author: 'Emily White',
      title: 'Operations Manager, Apex Corp.',
    },
  ];

  const [currentIndex, setCurrentIndex] = useState(0);

  const nextTestimonial = () => {
    setCurrentIndex((prevIndex) => (prevIndex + 1) % testimonials.length);
  };

  const prevTestimonial = () => {
    setCurrentIndex((prevIndex) => (prevIndex - 1 + testimonials.length) % testimonials.length);
  };

  const currentTestimonial = testimonials[currentIndex];

  return (
    <section id="testimonials" className="py-20 sm:py-24 md:py-32 bg-zinc-900 text-white">
      <div className="container mx-auto px-6 text-center">
        <h2 className="text-4xl sm:text-5xl font-bold mb-6">What Our Users Say</h2>
        <p className="text-xl text-zinc-300 mb-16 max-w-3xl mx-auto">
          Hear from satisfied customers who've transformed their workflow with NexusCore.
        </p>

        <div className="relative max-w-4xl mx-auto bg-zinc-800 p-8 sm:p-12 rounded-md">
          <blockquote className="text-2xl sm:text-3xl italic font-medium text-zinc-100 mb-8 leading-relaxed">
            "{currentTestimonial.quote}"
          </blockquote>
          <p className="text-lg font-semibold text-zinc-200">{currentTestimonial.author}</p>
          <p className="text-zinc-400">{currentTestimonial.title}</p>

          <button
            onClick={prevTestimonial}
            className="absolute left-4 top-1/2 -translate-y-1/2 bg-zinc-700 p-3 rounded-full hover:bg-zinc-600 transition duration-300 ease-in-out focus:outline-none focus:ring-2 focus:ring-zinc-500"
            aria-label="Previous testimonial"
          >
            <ChevronLeft size={24} className="text-white" />
          </button>
          <button
            onClick={nextTestimonial}
            className="absolute right-4 top-1/2 -translate-y-1/2 bg-zinc-700 p-3 rounded-full hover:bg-zinc-600 transition duration-300 ease-in-out focus:outline-none focus:ring-2 focus:ring-zinc-500"
            aria-label="Next testimonial"
          >
            <ChevronRight size={24} className="text-white" />
          </button>
        </div>

        <div className="flex justify-center mt-8 space-x-3">
          {testimonials.map((_, index) => (
            <button
              key={index}
              onClick={() => setCurrentIndex(index)}
              className={`w-3 h-3 rounded-full ${
                index === currentIndex ? 'bg-zinc-500' : 'bg-zinc-700 hover:bg-zinc-600'
              } transition duration-300 ease-in-out focus:outline-none focus:ring-2 focus:ring-zinc-500`}
              aria-label={`Go to testimonial ${index + 1}`}
            ></button>
          ))}
        </div>
      </div>
    </section>
  );
};

export default TestimonialCarousel;

